{
  "name": "filebrowser-ui",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "build": "tsc && node scripts/copy-assets.mjs",
    "test": "vitest run",
    "watch": "tsc --watch"
  },
  "devDependencies": {
    "typescript": "^5.6.3",
    "vitest": "^2.1.4",
    "happy-dom": "^15.7.4"
  }
}

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    environment: 'happy-dom',
    include: ['src/**/*.test.ts']
  }
});

import { describe, it, expect } from 'vitest';
import * as formatModule from './format';
import {
    formatBytes,
    normalizeRelativePath,
    joinPath,
    parentPath,
    basename,
    formatDate,
} from './format';

/* ===========================================================================
 * Module surface
 *
 * The spec requires that `src/format.ts` exports ONLY these six functions and
 * nothing else. This guard test pins that contract so a stray export does not
 * sneak in.
 * ========================================================================= */
describe('format module surface', () => {
    it('exports exactly the six documented functions', () => {
        expect(Object.keys(formatModule).sort()).toEqual(
            ['basename', 'formatBytes', 'formatDate', 'joinPath', 'normalizeRelativePath', 'parentPath'],
        );
    });
});

/* ===========================================================================
 * formatBytes
 *
 * Binary (1024-based) units: B, KB, MB, GB, TB.
 *  - bytes < 1024 render as an integer byte count (e.g. "1023 B").
 *  - bytes >= 1024 render with exactly one decimal place (e.g. "1.5 KB").
 * ========================================================================= */
describe('formatBytes', () => {
    it('formats zero bytes', () => {
        expect(formatBytes(0)).toBe('0 B');
    });

    it('formats a single byte', () => {
        expect(formatBytes(1)).toBe('1 B');
    });

    it('renders values under 1024 as an integer byte count with no decimals', () => {
        expect(formatBytes(1023)).toBe('1023 B');
        expect(formatBytes(512)).toBe('512 B');
    });

    it('renders exactly one kilobyte keeping the ".0" decimal', () => {
        // Spec: 1 decimal when >= 1024, so the trailing .0 is preserved.
        expect(formatBytes(1024)).toBe('1.0 KB');
    });

    it('formats 1536 bytes as 1.5 KB (the documented example)', () => {
        expect(formatBytes(1536)).toBe('1.5 KB');
    });

    it('rounds to one decimal place (2000 -> 2.0 KB)', () => {
        // 2000 / 1024 = 1.953125 -> one decimal rounds up to 2.0
        expect(formatBytes(2000)).toBe('2.0 KB');
    });

    it('formats exactly one megabyte keeping the ".0" decimal (documented example)', () => {
        expect(formatBytes(1048576)).toBe('1.0 MB');
    });

    it('formats 1.5 megabytes', () => {
        expect(formatBytes(1572864)).toBe('1.5 MB'); // 1.5 * 1024 * 1024
    });

    it('formats exactly one gigabyte', () => {
        expect(formatBytes(1073741824)).toBe('1.0 GB'); // 1024 ** 3
    });

    it('formats exactly one terabyte', () => {
        expect(formatBytes(1099511627776)).toBe('1.0 TB'); // 1024 ** 4
    });

    it('does not exceed the TB unit for very large values', () => {
        // 1024 ** 5 would be PB, but the documented unit set stops at TB.
        expect(formatBytes(1099511627776 * 2)).toBe('2.0 TB');
    });
});

/* ===========================================================================
 * normalizeRelativePath
 *
 *  - replace backslashes with '/'
 *  - trim leading/trailing '/'
 *  - collapse repeated '/'
 *  - drop '.' segments and '..' segments (filtered out, NOT resolved)
 *  - return '' for root/empty
 * ========================================================================= */
describe('normalizeRelativePath', () => {
    it('returns empty string for empty input', () => {
        expect(normalizeRelativePath('')).toBe('');
    });

    it('returns empty string for root', () => {
        expect(normalizeRelativePath('/')).toBe('');
    });

    it('returns empty string for a lone backslash (windows root)', () => {
        expect(normalizeRelativePath('\\')).toBe('');
    });

    it('returns empty string for an all-root input', () => {
        expect(normalizeRelativePath('///')).toBe('');
    });

    it('keeps a single clean segment unchanged', () => {
        expect(normalizeRelativePath('foo')).toBe('foo');
    });

    it('keeps multiple clean segments unchanged', () => {
        expect(normalizeRelativePath('foo/bar/baz')).toBe('foo/bar/baz');
    });

    it('trims a leading slash', () => {
        expect(normalizeRelativePath('/foo')).toBe('foo');
    });

    it('trims a trailing slash', () => {
        expect(normalizeRelativePath('foo/')).toBe('foo');
    });

    it('trims both leading and trailing slashes', () => {
        expect(normalizeRelativePath('/foo/bar/')).toBe('foo/bar');
    });

    it('collapses repeated slashes', () => {
        expect(normalizeRelativePath('foo//bar')).toBe('foo/bar');
        expect(normalizeRelativePath('//foo//bar//')).toBe('foo/bar');
    });

    it('replaces backslashes with forward slashes', () => {
        expect(normalizeRelativePath('foo\\bar')).toBe('foo/bar');
        expect(normalizeRelativePath('foo\\bar\\baz')).toBe('foo/bar/baz');
    });

    it('drops a single "." segment', () => {
        expect(normalizeRelativePath('foo/./bar')).toBe('foo/bar');
    });

    it('drops a trailing "." segment', () => {
        expect(normalizeRelativePath('foo/bar/.')).toBe('foo/bar');
    });

    it('drops a leading "." segment', () => {
        expect(normalizeRelativePath('./foo')).toBe('foo');
    });

    it('returns empty string for a lone "." or ".."', () => {
        expect(normalizeRelativePath('.')).toBe('');
        expect(normalizeRelativePath('..')).toBe('');
    });

    it('drops ".." segments rather than resolving them against the parent', () => {
        // Spec wording: "drop '.' segments and '..' segments". A ".." token is
        // filtered out of the segment list; it does NOT pop the previous segment.
        expect(normalizeRelativePath('foo/../bar')).toBe('foo/bar');
        expect(normalizeRelativePath('../foo')).toBe('foo');
    });

    it('drops mixed "." and ".." segments together with repeated slashes', () => {
        expect(normalizeRelativePath('a/../..//b')).toBe('a/b');
    });

    it('returns empty string when every segment is dropped', () => {
        expect(normalizeRelativePath('/./../')).toBe('');
    });
});

/* ===========================================================================
 * joinPath
 *
 * join with a single '/' then run the result through normalizeRelativePath.
 * ========================================================================= */
describe('joinPath', () => {
    it('joins two simple segments', () => {
        expect(joinPath('foo', 'bar')).toBe('foo/bar');
    });

    it('normalizes a trailing slash on the base', () => {
        expect(joinPath('foo/', 'bar')).toBe('foo/bar');
    });

    it('normalizes a leading slash on the name', () => {
        expect(joinPath('foo', '/bar')).toBe('foo/bar');
    });

    it('normalizes slashes on both sides', () => {
        expect(joinPath('foo/', '/bar')).toBe('foo/bar');
    });

    it('returns just the name when the base is empty', () => {
        expect(joinPath('', 'bar')).toBe('bar');
    });

    it('returns just the base when the name is empty', () => {
        // base + '/' + '' -> 'foo/' -> normalize -> 'foo'
        expect(joinPath('foo', '')).toBe('foo');
    });

    it('returns empty string when both parts are empty', () => {
        expect(joinPath('', '')).toBe('');
    });

    it('joins multi-segment paths', () => {
        expect(joinPath('a/b', 'c/d')).toBe('a/b/c/d');
    });

    it('normalizes backslashes in the joined result', () => {
        expect(joinPath('foo\\', 'bar')).toBe('foo/bar');
    });
});

/* ===========================================================================
 * parentPath
 *
 * Normalized parent relative path; '' when already at root.
 * ========================================================================= */
describe('parentPath', () => {
    it('returns empty string for an already-root path', () => {
        expect(parentPath('')).toBe('');
    });

    it('returns empty string for a single-segment path', () => {
        expect(parentPath('foo')).toBe('');
    });

    it('returns the parent of a two-segment path', () => {
        expect(parentPath('foo/bar')).toBe('foo');
    });

    it('returns the parent of a deeper path', () => {
        expect(parentPath('a/b/c')).toBe('a/b');
    });

    it('normalizes before computing the parent', () => {
        expect(parentPath('/foo/bar/')).toBe('foo');
    });

    it('normalizes "." segments before computing the parent', () => {
        expect(parentPath('a/./b')).toBe('a');
    });

    it('normalizes backslashes before computing the parent', () => {
        expect(parentPath('foo\\bar\\baz')).toBe('foo/bar');
    });
});

/* ===========================================================================
 * basename
 *
 * The last segment of the normalized path.
 * ========================================================================= */
describe('basename', () => {
    it('returns empty string for an empty path', () => {
        expect(basename('')).toBe('');
    });

    it('returns the single segment of a shallow path', () => {
        expect(basename('foo')).toBe('foo');
    });

    it('returns the last segment of a multi-segment path', () => {
        expect(basename('foo/bar')).toBe('bar');
    });

    it('returns the last segment of a deeper path', () => {
        expect(basename('a/b/c')).toBe('c');
    });

    it('normalizes leading/trailing slashes before taking the last segment', () => {
        expect(basename('/foo/bar/')).toBe('bar');
    });

    it('normalizes backslashes before taking the last segment', () => {
        expect(basename('foo\\bar')).toBe('bar');
    });

    it('ignores a trailing "." segment when computing the basename', () => {
        expect(basename('foo/bar/.')).toBe('bar');
    });
});

/* ===========================================================================
 * formatDate
 *
 * Parse an ISO date string; return '' for empty/invalid; otherwise render as
 * 'yyyy-MM-dd HH:mm' (local calendar time). The offset-free ISO datetimes used
 * below are parsed as local time, so the expected output is stable regardless
 * of the host time zone for a manual local-getter formatter.
 * ========================================================================= */
describe('formatDate', () => {
    it('returns empty string for an empty input', () => {
        expect(formatDate('')).toBe('');
    });

    it('returns empty string for a non-date string', () => {
        expect(formatDate('not-a-date')).toBe('');
    });

    it('returns empty string for arbitrary garbage', () => {
        expect(formatDate('abc')).toBe('');
    });

    it('does not throw for invalid input', () => {
        expect(() => formatDate('nope')).not.toThrow();
    });

    it('formats a local datetime as yyyy-MM-dd HH:mm', () => {
        expect(formatDate('2023-06-15T09:05:00')).toBe('2023-06-15 09:05');
    });

    it('formats an evening datetime', () => {
        expect(formatDate('2024-02-29T23:59:00')).toBe('2024-02-29 23:59');
    });

    it('pads single-digit month, day, hour and minute with a leading zero', () => {
        expect(formatDate('2023-01-05T08:02:00')).toBe('2023-01-05 08:02');
    });

    it('drops seconds (only year-month-day hour:minute are rendered)', () => {
        expect(formatDate('2023-06-15T09:05:45')).toBe('2023-06-15 09:05');
    });
});

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { ApiClient, type FileEntry, type BrowseResult, type SearchResult } from './api';

/**
 * Builds a minimal fetch Response stand-in for the mocked global fetch.
 * `json()` returns the parsed body; `text()` returns the raw text (defaults to
 * the JSON-stringified body). `ok` is derived from status unless overridden.
 */
function mockResponse(opts: {
  ok?: boolean;
  status?: number;
  body?: unknown;
  text?: string;
}): Response {
  const status = opts.status ?? 200;
  const ok = opts.ok ?? (status >= 200 && status < 300);
  const text = opts.text ?? JSON.stringify(opts.body ?? {});
  return {
    ok,
    status,
    text: async () => text,
    json: async () => (opts.body ?? (opts.text ? JSON.parse(opts.text) : {})),
  } as unknown as Response;
}

describe('ApiClient', () => {
  let fetchMock: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    fetchMock = vi.fn();
    vi.stubGlobal('fetch', fetchMock);
  });

  afterEach(() => {
    vi.unstubAllGlobals();
    vi.restoreAllMocks();
  });

  describe('constructor', () => {
    it('defaults baseUrl to /api/files', () => {
      const client = new ApiClient();
      expect(client.downloadUrl('x')).toBe('/api/files/download?path=x');
    });

    it('honors a custom baseUrl', () => {
      const client = new ApiClient('/custom/api');
      expect(client.downloadUrl('x')).toBe('/custom/api/download?path=x');
    });
  });

  describe('browse', () => {
    it('GETs the browse endpoint with an encoded path and returns parsed JSON', async () => {
      const client = new ApiClient();
      const entries: FileEntry[] = [
        { name: 'a.txt', path: '/root/a.txt', isDirectory: false, size: 10, lastModified: '2024-01-01T00:00:00Z' },
      ];
      const result: BrowseResult = {
        path: '/root',
        parent: '/',
        entries,
        folderCount: 0,
        fileCount: 1,
        totalSize: 10,
      };
      fetchMock.mockResolvedValueOnce(mockResponse({ body: result }));

      const data = await client.browse('/root');

      expect(fetchMock).toHaveBeenCalledTimes(1);
      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/browse?path=' + encodeURIComponent('/root'));
      expect(init?.method).toBe('GET');
      expect(data).toEqual(result);
    });

    it('encodes special characters in the path', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(
        mockResponse({ body: { path: '', parent: null, entries: [], folderCount: 0, fileCount: 0, totalSize: 0 } })
      );
      const tricky = '/foo bar/baz?x=1&y=2';
      await client.browse(tricky);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/browse?path=' + encodeURIComponent(tricky));
    });

    it('throws an Error containing status and response text on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 404, text: 'Not Found' }));

      await expect(client.browse('/missing')).rejects.toThrow('404: Not Found');
      await expect(client.browse('/missing')).rejects.toBeInstanceOf(Error);
    });

    it('throws a plain Error instance (not a string) on failure', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValue(mockResponse({ status: 500, text: 'boom' }));
      await expect(client.browse('/x')).rejects.toBeInstanceOf(Error);
    });
  });

  describe('search', () => {
    it('GETs the search endpoint with encoded query and path and returns parsed JSON', async () => {
      const client = new ApiClient();
      const results: FileEntry[] = [
        { name: 'match.txt', path: '/root/match.txt', isDirectory: false, size: 5, lastModified: '2024-02-02T00:00:00Z' },
      ];
      const out: SearchResult = { query: 'mat', path: '/root', results };
      fetchMock.mockResolvedValueOnce(mockResponse({ body: out }));

      const data = await client.search('mat', '/root');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe(
        '/api/files/search?query=' + encodeURIComponent('mat') + '&path=' + encodeURIComponent('/root')
      );
      expect(init?.method).toBe('GET');
      expect(data).toEqual(out);
    });

    it('encodes special characters in both query and path', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(
        mockResponse({ body: { query: '', path: '', results: [] } })
      );
      const q = 'a b&c';
      const p = '/dir x/y?z=1';
      await client.search(q, p);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/search?query=' + encodeURIComponent(q) + '&path=' + encodeURIComponent(p));
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 400, text: 'Bad Request' }));
      await expect(client.search('q', '/p')).rejects.toThrow('400: Bad Request');
    });
  });

  describe('upload', () => {
    it('POSTs multipart form data with a file field named "file" and returns parsed JSON', async () => {
      const client = new ApiClient();
      const file = new File(['hello'], 'hello.txt', { type: 'text/plain' });
      fetchMock.mockResolvedValueOnce(mockResponse({ body: { path: '/root/hello.txt' } }));

      const data = await client.upload('/root', file);

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/upload?path=' + encodeURIComponent('/root'));
      expect(init?.method).toBe('POST');
      const body = init?.body;
      expect(body).toBeInstanceOf(FormData);
      expect((body as FormData).get('file')).toBe(file);
      expect(data).toEqual({ path: '/root/hello.txt' });
    });

    it('encodes the destination path in the query string', async () => {
      const client = new ApiClient();
      const file = new File(['x'], 'x.txt');
      fetchMock.mockResolvedValueOnce(mockResponse({ body: { path: '' } }));
      const dest = '/some dir/sub?x=1';
      await client.upload(dest, file);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/upload?path=' + encodeURIComponent(dest));
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      const file = new File(['x'], 'x.txt');
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 413, text: 'Too Large' }));
      await expect(client.upload('/root', file)).rejects.toThrow('413: Too Large');
    });
  });

  describe('delete', () => {
    it('issues a DELETE to the delete endpoint and resolves to void on success', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 204, body: null }));

      const result = await client.delete('/root/old.txt');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/delete?path=' + encodeURIComponent('/root/old.txt'));
      expect(init?.method).toBe('DELETE');
      expect(result).toBeUndefined();
    });

    it('encodes the path', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 204 }));
      const p = '/a b/c?d=1';
      await client.delete(p);
      const [url] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/delete?path=' + encodeURIComponent(p));
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 403, text: 'Forbidden' }));
      await expect(client.delete('/nope')).rejects.toThrow('403: Forbidden');
    });
  });

  describe('move', () => {
    it('POSTs JSON { sourcePath, destinationPath } with Content-Type application/json and resolves void', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200, body: {} }));

      const result = await client.move('/a/b.txt', '/c/b.txt');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/move');
      expect(init?.method).toBe('POST');
      const headers = init?.headers as Record<string, string>;
      expect(headers['Content-Type']).toBe('application/json');
      expect(JSON.parse(init!.body as string)).toEqual({ sourcePath: '/a/b.txt', destinationPath: '/c/b.txt' });
      expect(result).toBeUndefined();
    });

    it('does not encode paths because they ride in a JSON body', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200 }));
      await client.move('/a b/c?x=1', '/d e/f?y=2');
      const body = JSON.parse(fetchMock.mock.calls[0][1].body as string);
      expect(body).toEqual({ sourcePath: '/a b/c?x=1', destinationPath: '/d e/f?y=2' });
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 409, text: 'Conflict' }));
      await expect(client.move('/a', '/b')).rejects.toThrow('409: Conflict');
    });
  });

  describe('copy', () => {
    it('POSTs JSON { sourcePath, destinationPath } with Content-Type application/json and resolves void', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200, body: {} }));

      const result = await client.copy('/a/b.txt', '/c/b.txt');

      const [url, init] = fetchMock.mock.calls[0];
      expect(url).toBe('/api/files/copy');
      expect(init?.method).toBe('POST');
      const headers = init?.headers as Record<string, string>;
      expect(headers['Content-Type']).toBe('application/json');
      expect(JSON.parse(init!.body as string)).toEqual({ sourcePath: '/a/b.txt', destinationPath: '/c/b.txt' });
      expect(result).toBeUndefined();
    });

    it('sends the raw paths in the JSON body', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 200 }));
      await client.copy('/src dir/f?x=1', '/dst dir/g?y=2');
      const body = JSON.parse(fetchMock.mock.calls[0][1].body as string);
      expect(body).toEqual({ sourcePath: '/src dir/f?x=1', destinationPath: '/dst dir/g?y=2' });
    });

    it('throws on non-2xx', async () => {
      const client = new ApiClient();
      fetchMock.mockResolvedValueOnce(mockResponse({ status: 500, text: 'Server Error' }));
      await expect(client.copy('/a', '/b')).rejects.toThrow('500: Server Error');
    });
  });

  describe('downloadUrl', () => {
    it('returns the encoded download URL synchronously without calling fetch', () => {
      const client = new ApiClient();
      const url = client.downloadUrl('/root/file.txt');
      expect(url).toBe('/api/files/download?path=' + encodeURIComponent('/root/file.txt'));
      expect(fetchMock).not.toHaveBeenCalled();
    });

    it('encodes special characters', () => {
      const client = new ApiClient();
      const tricky = '/a b/c?d=1&e=2';
      expect(client.downloadUrl(tricky)).toBe('/api/files/download?path=' + encodeURIComponent(tricky));
    });

    it('respects a custom baseUrl', () => {
      const client = new ApiClient('/api/v2/files');
      expect(client.downloadUrl('x')).toBe('/api/v2/files/download?path=x');
    });
  });

  describe('shared response types', () => {
    it('FileEntry shape matches the DTO contract', () => {
      const entry: FileEntry = {
        name: 'file.txt',
        path: '/root/file.txt',
        isDirectory: false,
        size: 123,
        lastModified: '2024-01-01T00:00:00Z',
      };
      expect(entry.name).toBe('file.txt');
      expect(entry.isDirectory).toBe(false);
    });

    it('BrowseResult shape matches the DTO contract including nullable parent', () => {
      const result: BrowseResult = {
        path: '/root',
        parent: null,
        entries: [],
        folderCount: 0,
        fileCount: 0,
        totalSize: 0,
      };
      expect(result.parent).toBeNull();
      expect(Array.isArray(result.entries)).toBe(true);
    });

    it('SearchResult shape matches the DTO contract', () => {
      const result: SearchResult = {
        query: 'foo',
        path: '/root',
        results: [
          { name: 'foo.txt', path: '/root/foo.txt', isDirectory: false, size: 1, lastModified: '2024-01-01T00:00:00Z' },
        ],
      };
      expect(result.results).toHaveLength(1);
    });
  });
});

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import {
  parseHash,
  toBrowseHash,
  toSearchHash,
  getCurrentRoute,
  subscribe,
  navigate,
  type Route,
  type View,
} from './router';

describe('parseHash', () => {
  describe('browse routes', () => {
    it('parses #/browse with no segments to an empty path', () => {
      expect(parseHash('#/browse')).toEqual({ view: 'browse', path: '', query: '' });
    });

    it('parses #/browse/ (trailing slash, no segments) to an empty path', () => {
      expect(parseHash('#/browse/')).toEqual({ view: 'browse', path: '', query: '' });
    });

    it('parses a single browse segment', () => {
      expect(parseHash('#/browse/docs')).toEqual({ view: 'browse', path: 'docs', query: '' });
    });

    it('parses multiple browse segments joined by /', () => {
      expect(parseHash('#/browse/docs/2024/reports')).toEqual({
        view: 'browse',
        path: 'docs/2024/reports',
        query: '',
      });
    });

    it('URL-decodes percent-encoded browse segments', () => {
      expect(parseHash('#/browse/hello%20world')).toEqual({
        view: 'browse',
        path: 'hello world',
        query: '',
      });
    });

    it('URL-decodes each segment independently', () => {
